questions.solution:
@Composable
fun CustomToggle(isOn: Boolean, onToggle: () -> Unit) {
    Box(
        modifier = Modifier
            .size(56.dp, 28.dp)
            .background(
                if (isOn) Color.Green else Color.Gray,
                RoundedCornerShape(14.dp)
            )
            .toggleable(
                value = isOn,
                onValueChange = { onToggle() },
                role = Role.Switch
            )
            .semantics {
                stateDescription = if (isOn) "On" else "Off"
            }
    ) {
        Box(
            modifier = Modifier
                .size(24.dp)
                .offset(x = if (isOn) 28.dp else 2.dp, y = 2.dp)
                .background(Color.White, CircleShape)
        )
    }
}

