questions.solution:
@Composable
fun PriceTag(dollars: Int, cents: Int) {
    Row(
        modifier = Modifier.clearAndSetSemantics {
            contentDescription = "$dollars dollars and $cents cents"
        }
    ) {
        Text(
            text = "$",
            style = MaterialTheme.typography.bodySmall
        )
        Text(
            text = "$dollars",
            style = MaterialTheme.typography.headlineLarge
        )
        Text(
            text = ".$cents",
            style = MaterialTheme.typography.bodySmall
        )
    }
}
